CREATE TABLE IF NOT EXISTS professional_financial_accounts (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, provider_name VARCHAR(60) NOT NULL DEFAULT 'MOCK_PROVIDER', account_token VARCHAR(120) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'ACTIVE');
CREATE TABLE IF NOT EXISTS professional_receivables (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, service_order_id BIGINT NULL, gross_amount NUMERIC(14,2) NOT NULL, net_amount NUMERIC(14,2) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'OPEN');
CREATE TABLE IF NOT EXISTS professional_payout_rules (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, rule_type VARCHAR(30) NOT NULL, execution_frequency VARCHAR(30) NOT NULL, discount_percentage NUMERIC(7,4) NOT NULL DEFAULT 0, is_auto BOOLEAN NOT NULL DEFAULT FALSE);
CREATE TABLE IF NOT EXISTS professional_payout_requests (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, requested_amount NUMERIC(14,2) NOT NULL, status VARCHAR(20) NOT NULL DEFAULT 'REQUESTED', requested_at TIMESTAMP NOT NULL DEFAULT NOW(), approved_by BIGINT NULL, approved_at TIMESTAMP NULL);
CREATE TABLE IF NOT EXISTS professional_payout_statements (id BIGSERIAL PRIMARY KEY, payout_request_id BIGINT NOT NULL REFERENCES professional_payout_requests(id), statement_json JSONB NOT NULL, generated_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE TABLE IF NOT EXISTS professional_payout_locks (id BIGSERIAL PRIMARY KEY, tenant_id BIGINT NOT NULL, professional_id BIGINT NOT NULL, lock_reason VARCHAR(200) NOT NULL, is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMP NOT NULL DEFAULT NOW());
CREATE OR REPLACE VIEW vw_professional_payouts AS SELECT ppr.tenant_id,ppr.professional_id,ppr.requested_amount,ppr.status,ppr.requested_at FROM professional_payout_requests ppr;
